import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { ToastContainer, toast } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";
import "./Delivery.css";

const Delivery = () => {
  const navigate = useNavigate();

  const [form, setForm] = useState({
    fullName: "",
    email: "",
    phone: "",
    country: "",
    address: "",
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    // Show non-blocking notification
    toast.success("Delivery details submitted successfully!", {
      position: "top-right",
      autoClose: 2000,
    });

    // Navigate to Payment page after short delay
    setTimeout(() => {
      navigate("/payment");
    }, 2000); // 2 seconds delay for notification
  };

  return (
    <div className="delivery-page">
      <ToastContainer />
      <div className="delivery-card">
        <h2>Delivery Information</h2>
        <p>Enter your delivery details below</p>

        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Full Name</label>
            <input
              type="text"
              name="fullName"
              placeholder="John Doe"
              value={form.fullName}
              onChange={handleChange}
              required
            />
          </div>

          <div className="form-group">
            <label>Email</label>
            <input
              type="email"
              name="email"
              placeholder="example@email.com"
              value={form.email}
              onChange={handleChange}
              required
            />
          </div>

          <div className="form-group">
            <label>Contact Number</label>
            <input
              type="tel"
              name="phone"
              placeholder="+60 12 345 6789"
              value={form.phone}
              onChange={handleChange}
              required
            />
          </div>

          <div className="form-group">
            <label>Country</label>
            <input
              type="text"
              name="country"
              placeholder="Malaysia"
              value={form.country}
              onChange={handleChange}
              required
            />
          </div>

          <div className="form-group">
            <label>Full Address</label>
            <textarea
              name="address"
              placeholder="Street, City, State, Postal Code"
              value={form.address}
              onChange={handleChange}
              required
            />
          </div>

          <button type="submit" className="delivery-btn">
            Confirm Delivery
          </button>
        </form>
      </div>
    </div>
  );
};

export default Delivery;
